export function resolveDoc(key: string): DocArticle {
  if (DOCS[key]) return DOCS[key];
  const lc = (key || '').toLowerCase();
  if (lc.includes('perspective') || lc.includes('관점')) return DOCS['perspectives'];
  if (lc.includes('oah agent cli') || lc.includes('os ai')) return DOCS['oah-agent-cli'];
  const hit = Object.values(DOCS).find(d => d.title.toLowerCase() === lc);
  if (hit) return hit;
  return { id: '_placeholder', title: key || '문서', updated: '', intro: '이 항목의 문서는 준비 중입니다. (Help Center 문서 백엔드 연동 후 채워집니다.) 현재는 첫 매뉴얼인 OpenSphere Perspectives가 작성되어 있습니다.', sections: [{ bullets: ['좌측 목차에서 "10 Perspectives"를 참고하세요.'] }], links: [{ label: 'OpenSphere Perspectives 보기', to: 'perspectives' }] };
}
